15	function readPositiveInt(value: string | undefined, fallback: number): number {
16	    const parsed = Number.parseInt(value ?? '', 10);
17	    if (!Number.isFinite(parsed) || parsed <= 0) return fallback;
18	    return parsed;
19	}
