48	function readBoolean(value: string | undefined, fallback: boolean): boolean {
49	    if (!value) return fallback;
50	    const normalized = value.trim().toLowerCase();
51	    if (['1', 'true', 'yes', 'on'].includes(normalized)) return true;
52	    if (['0', 'false', 'no', 'off'].includes(normalized)) return false;
53	    return fallback;
